const body = $json.body || {};
const pdf_url = body.pdf_url || body.url || $json.pdf_url;
if (!pdf_url) throw new Error('Falta "pdf_url" en el body. Ej: { "pdf_url": "https://.../file.pdf" }');

const template_base_url = (body.template_base_url || 'http://149.130.164.187:2020').toString().replace(/\/+$/, '');
const extractor_url = body.extractor_url || 'http://149.130.164.187:5050/api/v1/extract-from-url';
const response_mode = body.response_mode || 'html';

return [{ json: { body, pdf_url, extractor_url, template_base_url, response_mode } }];

function baseName(p) {
  if (!p) return '';
  const s = p.toString();
  return s.includes('/') ? s.split('/').pop() : s.includes('\\') ? s.split('\\').pop() : s;
}

const items = $input.all();
if (!items.length) throw new Error('No input items');

const binaries = [];
const seenKeys = new Set();
for (let i = 0; i < items.length; i++) {
  const bin = items[i].binary || {};
  for (const [key, b] of Object.entries(bin)) {
    let uniq = key;
    if (seenKeys.has(uniq)) uniq = `${i}_${key}`;
    seenKeys.add(uniq);
    binaries.push({ uniqKey: uniq, b });
  }
}

const metaEntry = binaries.find(e => {
  const fn = (e.b.fileName || '').toString().toLowerCase();
  const base = baseName(fn);
  return base === 'metadata.json' || fn.endsWith('metadata.json');
}) || binaries.find(e => (e.b.fileName || '').toString().toLowerCase().includes('meta') && (e.b.mimeType || '').includes('json'));

if (!metaEntry) {
  throw new Error('No metadata.json found in extracted ZIP');
}
if (!metaEntry.b.data) throw new Error('metadata.json binary has no data');

let metadata;
try {
  const txt = Buffer.from(metaEntry.b.data, 'base64').toString('utf8');
  metadata = JSON.parse(txt);
} catch (e) {
  throw new Error(`Failed to parse metadata.json: ${e.message}`);
}

const lowerBase = (v) => baseName(v || '').toLowerCase();
const renderEntry = binaries.find(e => lowerBase(e.b.fileName) === 'page001_render_ocr.png')
  || binaries.find(e => lowerBase(e.b.fileName) === 'page001_render.png')
  || binaries.find(e => /page0*1[_-]?render[_-]?ocr\.png$/i.test(baseName(e.b.fileName || '')))
  || binaries.find(e => /page0*1[_-]?render\.png$/i.test(baseName(e.b.fileName || '')))
  || binaries.find(e => /render[_-]?ocr\.png$/i.test(baseName(e.b.fileName || '')))
  || binaries.find(e => /render\.png$/i.test(baseName(e.b.fileName || '')));

const renderFileName = renderEntry ? baseName(renderEntry.b.fileName || '') : null;

// Prioriza URL OCR para evitar limites de tamaño/dimensiones en LLM vision
const sessionId = metadata.session_id || null;
const baseUrl = metadata.base_url || null;
let renderPngUrl = metadata.render_ocr_png_url || metadata.render_png_url || null;
if (!renderPngUrl && sessionId && baseUrl && renderFileName) {
  renderPngUrl = `${baseUrl}/api/v1/images/${sessionId}/${renderFileName}`;
}

return [{
  json: {
    metadata,
    render_png_url: renderPngUrl,
    render_ocr_png_url: metadata.render_ocr_png_url || null,
    render_filename: renderFileName,
    session_id: sessionId,
    base_url: baseUrl,
  },
}];

// Build a compact prompt for Gemini using metadata.json
const parseMeta = $items('Parse Metadata')[0]?.json || {};
const metadata = parseMeta.metadata;

if (!metadata || !metadata.images) throw new Error('metadata.images missing');

const wireframeNode = $items('arma wireframe')[0]?.json;
let wireframeText = '';
if (wireframeNode) {
  if (Array.isArray(wireframeNode.content) && wireframeNode.content[0]?.text) {
    wireframeText = wireframeNode.content[0].text;
  } else {
    wireframeText = wireframeNode.text || wireframeNode.output || wireframeNode.response || JSON.stringify(wireframeNode).slice(0, 3000);
  }
}

const images = metadata.images.map(img => ({
  filename: img.filename,
  url: img.url,
  page_number: img.page_number,
  x0: img.x0, y0: img.y0, x1: img.x1, y1: img.y1,
  bbox_width: img.bbox_width, bbox_height: img.bbox_height
}));

const prompt = [
  'Eres un clasificador de imágenes dentro de un PDF. Usa el PDF y estas coordenadas para identificar cada imagen y su rol en una página web.',
  '',
  `CRÍTICO: Debes clasificar las ${images.length} imágenes del metadata. NO omitas ninguna imagen, incluso si son pequeñas, iconos o decorativas.`,
  '',
  'Tareas:',
  '1) OCR/identificación: deduce el contenido visual de cada imagen usando el PDF.',
  '2) Clasificación: asigna UNA etiqueta HTML de esta lista: header, nav, main, section, article, aside, footer.',
  `3) IMPORTANTE: La respuesta debe incluir TODAS las imágenes del metadata (${images.length} imágenes en total).`,
  '4) Responde SOLO con JSON válido (sin markdown) con la estructura:',
  '{"images":[{"filename":"...","url":"...","page_number":1,"bbox":{"x0":0,"y0":0,"x1":0,"y1":0},"label":"header|nav|...","ocr_text":"...","confidence":0.0}]}',
  '',
  'Notas:',
  '- El origen (0,0) es la esquina inferior izquierda de la página.',
  '- Usa las coordenadas para inferir ubicación (arriba=header, abajo=footer, lateral=aside, etc.).',
  '- Clasifica TODAS las imágenes, incluyendo logos, iconos, botones, y gráficos pequeños.',
  '',
  'Contexto adicional (wireframe previo):',
  wireframeText.slice(0, 2000) || '(sin wireframe)',
  '',
  'metadata:',
  JSON.stringify({
    pdf_file: metadata.pdf_file,
    total_pages: metadata.total_pages,
    total_images: metadata.total_images,
    render_dpi: metadata.render_dpi,
    note: metadata.note,
    images
  })
].join('\n');

return [{
  json: {
    ...parseMeta,
    prompt,
    wireframe_text: wireframeText,
    render_png_url: parseMeta.render_png_url || null,
    render_ocr_png_url: parseMeta.render_ocr_png_url || null,
  }
}];

function stripCodeFences(s) {
  if (!s) return s;
  const t = s.trim();
  if (t.startsWith('```')) {
    const firstNewline = t.indexOf('\n');
    const body = firstNewline >= 0 ? t.slice(firstNewline + 1) : '';
    const endFence = body.lastIndexOf('```');
    return (endFence >= 0 ? body.slice(0, endFence) : body).trim();
  }
  return t;
}

function pickText(obj) {
  if (!obj) return null;
  if (typeof obj === 'string') return obj;
  if (typeof obj.text === 'string') return obj.text;
  if (typeof obj.responseText === 'string') return obj.responseText;
  if (typeof obj.content === 'string') return obj.content;
  if (obj.content && obj.content.parts && Array.isArray(obj.content.parts)) {
    const part = obj.content.parts.find(p => typeof p.text === 'string');
    if (part) return part.text;
  }
  if (obj.candidates && Array.isArray(obj.candidates)) {
    for (const c of obj.candidates) {
      if (c && c.content) {
        if (typeof c.content === 'string') return c.content;
        if (c.content.parts && Array.isArray(c.content.parts)) {
          const part = c.content.parts.find(p => typeof p.text === 'string');
          if (part) return part.text;
        }
      }
      if (typeof c.text === 'string') return c.text;
    }
  }
  if (obj.content && Array.isArray(obj.content)) {
    const part = obj.content.find(p => typeof p.text === 'string');
    if (part) return part.text;
  }
  for (const key of ['response', 'data', 'output', 'result']) {
    if (obj[key]) { const t = pickText(obj[key]); if (t) return t; }
  }
  if (Array.isArray(obj)) { for (const it of obj) { const t = pickText(it); if (t) return t; } }
  return null;
}

const input = $json;
let text = pickText(input);
if (!text) throw new Error('No text response found from Gemini. Keys: ' + JSON.stringify(Object.keys(input || {})));

text = stripCodeFences(text);
let mapping;
try { mapping = JSON.parse(text); }
catch (e) { throw new Error('Failed to parse JSON from Gemini: ' + e.message + '\nRaw: ' + text.slice(0, 500)); }

return [{ json: { mapping } }];

const mapping = $json.mapping || {};
const mappedImages = Array.isArray(mapping.images) ? mapping.images : [];

const parseMeta = $items('Parse Metadata')[0]?.json || {};
const metadataImages = Array.isArray(parseMeta?.metadata?.images) ? parseMeta.metadata.images : [];
const renderPngUrl = parseMeta.render_png_url || null;
const renderOcrPngUrl = parseMeta.render_ocr_png_url || null;
const sessionId = parseMeta.session_id || null;
const pdfUrl = $items('Validate + Defaults')[0]?.json?.pdf_url || null;

const buildPromptNode = $items('Build Gemini Prompt con base de wireframe')[0]?.json || {};
const wireframeText = buildPromptNode.wireframe_text || '';

const ALLOWED = ['header', 'nav', 'main', 'section', 'article', 'aside', 'footer'];
const LABEL_SYNONYMS = {
  hero: 'main',
  body: 'main',
  content: 'main',
  promo: 'section',
  promociones: 'section',
  gallery: 'section',
  legal: 'footer',
  social: 'footer',
};

const normalizeLabel = (raw) => {
  const src = String(raw || '').trim().toLowerCase();
  if (!src) return 'section';
  if (ALLOWED.includes(src)) return src;
  if (LABEL_SYNONYMS[src]) return LABEL_SYNONYMS[src];
  if (src.includes('header')) return 'header';
  if (src.includes('nav')) return 'nav';
  if (src.includes('footer') || src.includes('legal')) return 'footer';
  if (src.includes('aside') || src.includes('sidebar') || src.includes('lateral')) return 'aside';
  if (src.includes('article') || src.includes('card')) return 'article';
  if (src.includes('main') || src.includes('hero')) return 'main';
  return 'section';
};

const mapByFilename = new Map(mappedImages.map((img) => [String(img.filename || ''), img]));
const mergedImages = metadataImages.map((metaImg) => {
  const fromModel = mapByFilename.get(String(metaImg.filename || '')) || {};
  const x0 = Number(metaImg.x0 ?? fromModel?.bbox?.x0 ?? 0);
  const y0 = Number(metaImg.y0 ?? fromModel?.bbox?.y0 ?? 0);
  const x1 = Number(metaImg.x1 ?? fromModel?.bbox?.x1 ?? 0);
  const y1 = Number(metaImg.y1 ?? fromModel?.bbox?.y1 ?? 0);

  return {
    filename: metaImg.filename,
    url: metaImg.url || fromModel.url || null,
    page_number: Number(metaImg.page_number || fromModel.page_number || 1),
    bbox: { x0, y0, x1, y1 },
    width: Math.max(0, x1 - x0),
    height: Math.max(0, y1 - y0),
    area: Math.max(0, x1 - x0) * Math.max(0, y1 - y0),
    y_center: (y0 + y1) / 2,
    ocr_text: fromModel.ocr_text || '',
    confidence: Number(fromModel.confidence ?? 0),
    label: normalizeLabel(fromModel.label),
  };
});

if (!mergedImages.length) {
  throw new Error('No hay imagenes para clasificar en componentes.');
}

const avg = (arr) => arr.length ? arr.reduce((a, b) => a + b, 0) / arr.length : null;
const headerYs = mergedImages.filter((x) => x.label === 'header').map((x) => x.y_center);
const footerYs = mergedImages.filter((x) => x.label === 'footer').map((x) => x.y_center);
// true => y pequeño está arriba (top-left). false => y grande está arriba (bottom-left).
let originTopLeft = true;
if (headerYs.length && footerYs.length) {
  originTopLeft = avg(headerYs) < avg(footerYs);
}

const topFirstComparator = (a, b) => {
  const ay = Number(a?.y_center ?? 0);
  const by = Number(b?.y_center ?? 0);
  const primary = originTopLeft ? (ay - by) : (by - ay);
  if (primary !== 0) return primary;
  return Number(a?.bbox?.x0 ?? 0) - Number(b?.bbox?.x0 ?? 0);
};

const pageStats = {};
for (const img of mergedImages) {
  const p = img.page_number;
  if (!pageStats[p]) pageStats[p] = { maxX: 0, maxY: 0, minX: Number.POSITIVE_INFINITY, minY: Number.POSITIVE_INFINITY };
  pageStats[p].maxX = Math.max(pageStats[p].maxX, img.bbox.x1 || 0);
  pageStats[p].maxY = Math.max(pageStats[p].maxY, img.bbox.y1 || 0);
  pageStats[p].minX = Math.min(pageStats[p].minX, img.bbox.x0 || 0);
  pageStats[p].minY = Math.min(pageStats[p].minY, img.bbox.y0 || 0);
}

const rowsByPage = {};
for (const [pageRaw, stats] of Object.entries(pageStats)) {
  const page = Number(pageRaw);
  const pageImages = mergedImages
    .filter((img) => img.page_number === page)
    .sort(topFirstComparator);

  const pageHeight = Math.max(1, stats.maxY - Math.min(0, stats.minY));
  const verticalThreshold = Math.max(90, pageHeight * 0.06);

  const rows = [];
  for (const img of pageImages) {
    let target = null;
    for (const row of rows) {
      const centerGap = Math.abs(img.y_center - row.y_center);
      const overlap = Math.min(img.bbox.y1, row.maxY) - Math.max(img.bbox.y0, row.minY);
      if (centerGap <= verticalThreshold || overlap >= -10) {
        target = row;
        break;
      }
    }

    if (!target) {
      rows.push({
        images: [img],
        minY: img.bbox.y0,
        maxY: img.bbox.y1,
        y_center: img.y_center,
        area: img.area,
      });
    } else {
      target.images.push(img);
      target.minY = Math.min(target.minY, img.bbox.y0);
      target.maxY = Math.max(target.maxY, img.bbox.y1);
      target.y_center = (target.minY + target.maxY) / 2;
      target.area += img.area;
    }
  }

  const sortedRows = rows.sort(topFirstComparator);
  const pageArea = Math.max(1, (stats.maxX - stats.minX) * pageHeight);

  for (let i = 0; i < sortedRows.length; i++) {
    const row = sortedRows[i];
    const rowAreaRatio = row.area / pageArea;
    if (row.images.length > 1 || rowAreaRatio > 0.01) continue;

    let nearest = -1;
    let bestGap = Number.POSITIVE_INFINITY;
    for (let j = 0; j < sortedRows.length; j++) {
      if (j === i) continue;
      const gap = Math.abs(sortedRows[j].y_center - row.y_center);
      if (gap < bestGap) {
        bestGap = gap;
        nearest = j;
      }
    }

    if (nearest >= 0 && bestGap <= verticalThreshold * 1.8) {
      const dst = sortedRows[nearest];
      dst.images.push(...row.images);
      dst.minY = Math.min(dst.minY, row.minY);
      dst.maxY = Math.max(dst.maxY, row.maxY);
      dst.y_center = (dst.minY + dst.maxY) / 2;
      dst.area += row.area;
      row.images = [];
    }
  }

  const compactRows = sortedRows.filter((r) => r.images.length > 0);
  const maxRowsByPage = page === 1 ? 6 : page === 2 ? 3 : 2;

  while (compactRows.length > maxRowsByPage) {
    let idx = 0;
    let minGap = Number.POSITIVE_INFINITY;
    for (let i = 0; i < compactRows.length - 1; i++) {
      const gap = Math.abs(compactRows[i].y_center - compactRows[i + 1].y_center);
      if (gap < minGap) {
        minGap = gap;
        idx = i;
      }
    }

    const a = compactRows[idx];
    const b = compactRows[idx + 1];
    a.images.push(...b.images);
    a.minY = Math.min(a.minY, b.minY);
    a.maxY = Math.max(a.maxY, b.maxY);
    a.y_center = (a.minY + a.maxY) / 2;
    a.area += b.area;
    compactRows.splice(idx + 1, 1);
  }

  for (const row of compactRows) {
    row.images.sort((a, b) => Number(a?.bbox?.x0 ?? 0) - Number(b?.bbox?.x0 ?? 0));
  }

  rowsByPage[page] = compactRows.sort(topFirstComparator);
}

const pages = Object.keys(rowsByPage).map(Number).sort((a, b) => a - b);
const components = [];
let globalIndex = 0;

for (const page of pages) {
  const rows = rowsByPage[page] || [];
  const stats = pageStats[page] || { maxY: 1, minY: 0, maxX: 620, minX: 0 };
  const pageHeight = Math.max(1, stats.maxY - Math.min(0, stats.minY));
  const pageArea = Math.max(1, (stats.maxX - stats.minX) * pageHeight);

  rows.forEach((row, rowIndex) => {
    globalIndex += 1;

    const yNorm = (row.y_center - stats.minY) / Math.max(1, stats.maxY - stats.minY);
    const topness = originTopLeft ? (1 - yNorm) : yNorm;

    const rowAreaRatio = row.area / pageArea;
    const labels = row.images.map((img) => img.label).filter(Boolean);
    const labelFreq = labels.reduce((acc, x) => {
      acc[x] = (acc[x] || 0) + 1;
      return acc;
    }, {});
    const dominantLabel = Object.entries(labelFreq).sort((a, b) => b[1] - a[1])[0]?.[0] || 'section';

    let sectionLabel = dominantLabel;
    if (rowIndex === 0 && page === 1 && (dominantLabel === 'header' || topness > 0.8)) sectionLabel = 'header';
    else if (rowAreaRatio > 0.2 || dominantLabel === 'main') sectionLabel = 'main';
    else if (rowIndex === rows.length - 1 && page === pages[pages.length - 1] && topness < 0.25) sectionLabel = 'footer';
    else if (!ALLOWED.includes(sectionLabel)) sectionLabel = 'section';

    const maxConf = Math.max(...row.images.map((img) => Number(img.confidence || 0)), 0);
    const anchorHits = [...new Set(labels.length ? labels : [sectionLabel])];

    components.push({
      component_id: `section_${String(globalIndex).padStart(2, '0')}_${sectionLabel}_p${page}_r${rowIndex}`,
      section_label: sectionLabel,
      order: globalIndex - 1,
      images: row.images.map((img) => ({
        filename: img.filename,
        url: img.url,
        bbox: img.bbox || {},
        ocr_text: img.ocr_text || '',
        confidence: Number(img.confidence || 0),
        page_number: img.page_number || 1,
      })),
      render_png_url: renderPngUrl,
      render_ocr_png_url: renderOcrPngUrl,
      pdf_url: pdfUrl,
      session_id: sessionId,
      wireframe_text: wireframeText,
      presence_confidence: maxConf,
      anchor_hits: anchorHits,
      coordinate_origin: originTopLeft ? 'top_left' : 'bottom_left',
      skip_generation: false,
    });
  });
}

if (!components.length) {
  throw new Error('No se pudieron construir componentes desde metadata + OCR.');
}

return components.map((c) => ({ json: c }));

const items = $input.all().map((item) => item.json);
items.sort((a, b) => (a.order || 0) - (b.order || 0));
return items.map((json) => ({ json }));

const item = { ...$json };
const round4 = n => Number(Number(n || 0).toFixed(4));

// Usar las imagenes mapeadas al componente
const images = (item.images || []).slice(0, 15).map(img => ({
  src: img.url || '',
  filename: img.filename || '',
  bbox: img.bbox || {},
  ocr_text: img.ocr_text || '',
  confidence: img.confidence || 0,
  page_number: img.page_number || 1,
}));

const bboxes = images.map(i => i.bbox).filter(b => b && typeof b.x0 === 'number' && typeof b.y0 === 'number');
let contentBounds = null;
if (bboxes.length > 0) {
  contentBounds = {
    x0: round4(Math.min(...bboxes.map(b => b.x0))),
    y0: round4(Math.min(...bboxes.map(b => b.y0))),
    x1: round4(Math.max(...bboxes.map(b => b.x1))),
    y1: round4(Math.max(...bboxes.map(b => b.y1))),
  };
}

const evidence = {
  component_id: item.component_id,
  section_label: item.section_label,
  render_png_url: item.render_png_url,
  render_ocr_png_url: item.render_ocr_png_url || null,
  pdf_url: item.pdf_url,
  images,
  content_bounds: contentBounds,
  wireframe_text: (item.wireframe_text || '').slice(0, 2000),
  presence_confidence: item.presence_confidence,
};

item.component_payload = JSON.stringify(evidence, null, 2);
return [{ json: item }];

const comp = $json || {};
const componentId = comp.component_id || '';
const sectionLabel = comp.section_label || componentId;
const renderPngUrl = comp.render_ocr_png_url || comp.render_png_url || null;

let evidence = {};
try { evidence = JSON.parse(comp.component_payload || '{}'); } catch(e) {}

const images = evidence.images || comp.images || [];
const wireframeText = (evidence.wireframe_text || comp.wireframe_text || '').slice(0, 1500);

const imageLines = images.map((img, i) => {
  const b = img.bbox || {};
  const bboxStr = typeof b.x0 === 'number'
    ? `PDF pts: x0=${Math.round(b.x0)}, y0=${Math.round(b.y0)}, x1=${Math.round(b.x1)}, y1=${Math.round(b.y1)}`
    : 'posicion desconocida';
  return `  [IMG ${i + 1}] Archivo: ${img.filename || ''}\n  URL: ${img.src || img.url || ''}\n  OCR: ${img.ocr_text || 'sin texto detectado'}\n  ${bboxStr}`;
}).join('\n\n');

const imagesSummary = images.length > 0 ? imageLines : '  (sin imagenes asignadas a esta seccion)';

const claude_prompt = `Eres un generador experto de HTML para emails. Construye UNA seccion de email newsletter.

SECCION A CONSTRUIR: "${sectionLabel}"
COMPONENT_ID (obligatorio en salida): "${componentId}"

IMAGENES DISPONIBLES (ya mapeadas a esta seccion por OCR):
${imagesSummary}

WIREFRAME REFERENCIA (contexto global del documento):
${wireframeText}

INSTRUCCIONES:
1. Usa EXACTAMENTE las URLs de imagen de arriba en src/background. NO uses otras URLs.
2. HTML email valido: SOLO tablas y CSS inline (Outlook/Gmail).
3. Ancho maximo contenedor: 620px.
4. ANTI-DESBORDE (OBLIGATORIO):
   - Toda imagen debe quedar dentro de su contenedor.
   - En cada <img> usa SIEMPRE: style="display:block; width:100%; max-width:100%; height:auto; object-fit:cover;"
   - Nunca uses width/height que exceda el <td> padre.
   - En contenedores de imagen usa style con overflow:hidden.
5. Si la seccion tiene 2 columnas, usa dos <td width="310" style="width:310px;max-width:310px;overflow:hidden;">.
6. Respeta layout y proporciones del render.png.
7. No uses markdown ni triple backticks.

FORMATO DE SALIDA (SOLO JSON valido):
{"component_id":"${componentId}","component_html":"<table role=\\"none\\" ...>...</table>","changed":true,"reason":"string"}`;

return [{
  json: {
    ...comp,
    render_png_url: renderPngUrl,
    ocr_lines_count: images.length,
    claude_prompt,
  },
}];

// Obtener todos los componentes clasificados
const allComponents = $items('Clasifica PDF en componentes').map((i) => i.json);
if (!allComponents.length) throw new Error('No se encontraron componentes de Clasifica PDF en componentes.');

const requestInput = $items('Validate + Defaults')[0]?.json || {};
const responseMode = requestInput.response_mode || 'html';

const component_order = allComponents
  .slice()
  .sort((a, b) => Number(a.order || 0) - Number(b.order || 0))
  .map((c) => c.component_id);

const render_png_url = allComponents[0]?.render_png_url || null;
const pdf_url = allComponents[0]?.pdf_url || null;
const session_id = allComponents[0]?.session_id || null;

const extractText = (json) => {
  const candidates = [json?.content?.[0]?.text, json?.output, json?.text, json?.response, json?.content, json?.message, json?.result, json?.data];
  for (const v of candidates) {
    if (typeof v === 'string' && v.trim()) return v;
  }
  return JSON.stringify(json || {});
};

const decodeEsc = (value) => {
  const text = String(value || '');
  return text
    .replace(/\\n/g, '\n')
    .replace(/\\r/g, '\r')
    .replace(/\\t/g, '\t')
    .replace(/\\"/g, '"')
    .replace(/\\\//g, '/');
};

const sanitize = (html) => decodeEsc(html).replace(/src\s*=\s*"\s*(undefined|null)\s*"/gi, 'src=""');

const tryParseJson = (raw) => {
  let text = String(raw || '').trim();
  text = text.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/i, '').trim();
  try {
    return JSON.parse(text);
  } catch (_) {}

  const s = text.indexOf('{');
  const e = text.lastIndexOf('}');
  if (s >= 0 && e > s) {
    try {
      return JSON.parse(text.slice(s, e + 1));
    } catch (_) {}
  }
  return null;
};

const parseModelResult = (raw, fallbackComponentId) => {
  const text = String(raw || '').trim();
  const parsed = tryParseJson(text);
  if (parsed && typeof parsed === 'object') {
    const cid = String(parsed.component_id || fallbackComponentId || '').trim();
    const html = typeof parsed.component_html === 'string' ? parsed.component_html : '';
    if (cid && html.trim()) {
      return {
        component_id: cid,
        component_html: sanitize(html),
        changed: Boolean(parsed.changed),
        reason: parsed.reason || null,
        source: 'json',
      };
    }
  }

  const cidMatch = text.match(/"component_id"\s*:\s*"([^"]+)"/i);
  const componentId = (cidMatch?.[1] || fallbackComponentId || '').trim();

  const htmlFieldMatch = text.match(/"component_html"\s*:\s*"([\s\S]*?)"\s*(?:,\s*"|\}\s*$)/i);
  if (componentId && htmlFieldMatch?.[1]) {
    return {
      component_id: componentId,
      component_html: sanitize(htmlFieldMatch[1]),
      changed: true,
      reason: 'regex_component_html',
      source: 'regex_field',
    };
  }

  const tableMatch = text.match(/<table\b[\s\S]*?<\/table>/i);
  if (componentId && tableMatch?.[0]) {
    return {
      component_id: componentId,
      component_html: sanitize(tableMatch[0]),
      changed: true,
      reason: 'regex_table',
      source: 'regex_table',
    };
  }

  return null;
};

const avg = (arr) => arr.length ? arr.reduce((a, b) => a + b, 0) / arr.length : null;
const imageRowsAll = allComponents.flatMap((c) => (c.images || []).map((img) => ({
  y: (Number(img?.bbox?.y0 ?? 0) + Number(img?.bbox?.y1 ?? 0)) / 2,
  isHeader: c.section_label === 'header' || (c.anchor_hits || []).includes('header'),
  isFooter: c.section_label === 'footer' || (c.anchor_hits || []).includes('footer'),
})));
const headerYs = imageRowsAll.filter((x) => x.isHeader).map((x) => x.y);
const footerYs = imageRowsAll.filter((x) => x.isFooter).map((x) => x.y);
let originTopLeft = true;
if (headerYs.length && footerYs.length) {
  originTopLeft = avg(headerYs) < avg(footerYs);
} else if (typeof allComponents[0]?.coordinate_origin === 'string') {
  originTopLeft = allComponents[0].coordinate_origin === 'top_left';
}

const componentById = new Map(allComponents.map((c) => [c.component_id, c]));

const pageExtents = {};
for (const comp of allComponents) {
  for (const img of (comp.images || [])) {
    const p = Number(img?.page_number || 1);
    const x0 = Number(img?.bbox?.x0 ?? 0);
    const x1 = Number(img?.bbox?.x1 ?? 0);
    if (!pageExtents[p]) pageExtents[p] = { minX: Number.POSITIVE_INFINITY, maxX: Number.NEGATIVE_INFINITY };
    pageExtents[p].minX = Math.min(pageExtents[p].minX, x0);
    pageExtents[p].maxX = Math.max(pageExtents[p].maxX, x1);
  }
}
const pageWidthByPage = {};
for (const [k, v] of Object.entries(pageExtents)) {
  const width = Math.max(1, Number(v.maxX) - Number(v.minX));
  pageWidthByPage[Number(k)] = width;
}

const buildRowsFromImages = (imgs, yThreshold = 90) => {
  const sorted = [...imgs].sort((a, b) => {
    const ay = (Number(a?.bbox?.y0 ?? 0) + Number(a?.bbox?.y1 ?? 0)) / 2;
    const by = (Number(b?.bbox?.y0 ?? 0) + Number(b?.bbox?.y1 ?? 0)) / 2;
    const primary = originTopLeft ? (ay - by) : (by - ay);
    if (primary !== 0) return primary;
    return Number(a?.bbox?.x0 ?? 0) - Number(b?.bbox?.x0 ?? 0);
  });

  const rows = [];
  for (const img of sorted) {
    const y0 = Number(img?.bbox?.y0 ?? 0);
    const y1 = Number(img?.bbox?.y1 ?? 0);
    const yCenter = (y0 + y1) / 2;

    let row = null;
    for (const r of rows) {
      const gap = Math.abs(r.yCenter - yCenter);
      const overlap = Math.min(r.maxY, y1) - Math.max(r.minY, y0);
      if (gap <= yThreshold || overlap >= -8) {
        row = r;
        break;
      }
    }

    if (!row) {
      rows.push({ images: [img], minY: y0, maxY: y1, yCenter });
    } else {
      row.images.push(img);
      row.minY = Math.min(row.minY, y0);
      row.maxY = Math.max(row.maxY, y1);
      row.yCenter = (row.minY + row.maxY) / 2;
    }
  }

  for (const row of rows) {
    row.images.sort((a, b) => Number(a?.bbox?.x0 ?? 0) - Number(b?.bbox?.x0 ?? 0));
  }

  return rows.sort((a, b) => {
    const primary = originTopLeft ? (a.yCenter - b.yCenter) : (b.yCenter - a.yCenter);
    return primary;
  });
};

const clamp = (n, min, max) => Math.max(min, Math.min(max, n));

const buildFallbackComponentHtml = (componentId) => {
  const comp = componentById.get(componentId) || {};
  const imgs = Array.isArray(comp.images) ? comp.images.filter((x) => x?.url) : [];
  if (!imgs.length) return '';

  const yValues = imgs.flatMap((img) => [Number(img?.bbox?.y0 ?? 0), Number(img?.bbox?.y1 ?? 0)]);
  const pageNo = Number(imgs[0]?.page_number || 1);
  const pageWidth = Math.max(1, Number(pageWidthByPage[pageNo] || 620));
  const pageHeight = Math.max(1, Math.max(...yValues) - Math.min(...yValues));

  const rows = buildRowsFromImages(imgs, Math.max(70, pageHeight * 0.05));

  const rowHtml = rows.map((row) => {
    if (row.images.length === 1) {
      const img = row.images[0];
      const src = String(img?.url || '').trim();
      if (!src) return '';
      const alt = String(img?.ocr_text || img?.filename || 'imagen').replace(/"/g, '&quot;').slice(0, 180);
      const bboxWidth = Math.max(1, Number(img?.bbox?.x1 ?? 0) - Number(img?.bbox?.x0 ?? 0));
      const widthPx = clamp(Math.round((bboxWidth / pageWidth) * 620), 24, 620);
      const useFullWidth = widthPx >= 560;
      const align = useFullWidth ? 'left' : 'center';
      const widthAttr = useFullWidth ? '620' : String(widthPx);
      const widthStyle = useFullWidth ? 'width:100%;max-width:620px;' : `width:${widthPx}px;max-width:100%;`;

      return `<tr><td align="${align}" style="padding:0;overflow:hidden;"><img src="${src}" alt="${alt}" width="${widthAttr}" style="display:block;${widthStyle}height:auto;object-fit:contain;border:0;outline:none;text-decoration:none;"/></td></tr>`;
    }

    const widths = row.images.map((img) => Math.max(1, Number(img?.bbox?.x1 ?? 0) - Number(img?.bbox?.x0 ?? 0)));
    const totalWidth = Math.max(1, widths.reduce((a, b) => a + b, 0));

    const cols = row.images.map((img, idx) => {
      const src = String(img?.url || '').trim();
      if (!src) return '';
      const alt = String(img?.ocr_text || img?.filename || 'imagen').replace(/"/g, '&quot;').slice(0, 180);
      const pct = clamp(Math.round((widths[idx] / totalWidth) * 1000) / 10, 8, 92);
      return `<td valign="top" width="${pct}%" style="width:${pct}%;padding:0;overflow:hidden;"><img src="${src}" alt="${alt}" style="display:block;width:100%;max-width:100%;height:auto;object-fit:cover;border:0;outline:none;text-decoration:none;"/></td>`;
    }).join('');

    return `<tr><td style="padding:0;"><table role="none" border="0" cellpadding="0" cellspacing="0" width="100%" style="width:100%;"><tr>${cols}</tr></table></td></tr>`;
  }).join('');

  if (!rowHtml) return '';

  return `<table role="none" border="0" cellpadding="0" cellspacing="0" width="620" style="width:620px;max-width:620px;background:#ffffff;"><tr><td style="padding:0;"><!-- fallback_component:${componentId} --></td></tr>${rowHtml}</table>`;
};

const generatedById = {};
const parseErrors = [];
const modelItems = $items('Valida componente con Claude');
const preparedItems = $items('Prepara OCR por componente').map((i) => i.json || {});

for (let i = 0; i < modelItems.length; i++) {
  const item = modelItems[i];
  const fallbackComponentId = preparedItems[i]?.component_id || component_order[i] || '';
  const raw = extractText(item.json);
  const parsed = parseModelResult(raw, fallbackComponentId);

  if (!parsed || !parsed.component_id || !parsed.component_html) {
    parseErrors.push({ component_id: fallbackComponentId || null, reason: 'parse_failed' });
    continue;
  }

  generatedById[parsed.component_id] = {
    component_html: parsed.component_html,
    changed: Boolean(parsed.changed),
    reason: parsed.reason || null,
    source: parsed.source || 'unknown',
  };
}

const fallbackIds = [];
const htmlParts = [];
for (const componentId of component_order) {
  const generated = generatedById[componentId]?.component_html;
  const fallback = buildFallbackComponentHtml(componentId);
  const fragment = generated || fallback;
  if (!generated) fallbackIds.push(componentId);
  if (fragment) htmlParts.push(fragment);
}

const bodyContent = decodeEsc(htmlParts.join('\n'));
const htmlFinal = `<!DOCTYPE html>\n<html lang="es">\n<head>\n<meta charset="UTF-8">\n<meta name="viewport" content="width=device-width, initial-scale=1.0">\n<title>Newsletter</title>\n</head>\n<body style="margin:0;padding:0;background:#E0E0E0;">\n<table role="none" border="0" cellpadding="0" cellspacing="0" width="100%" style="width:100%;background:#E0E0E0;">\n<tr><td align="center" style="padding:0;">\n<table role="none" border="0" cellpadding="0" cellspacing="0" width="620" style="width:620px;max-width:620px;" class="container">\n<tr><td style="padding:0;">\n${bodyContent}\n</td></tr>\n</table>\n</td></tr>\n</table>\n</body>\n</html>`;

const generatedCount = Object.keys(generatedById).length;
const componentsSummary = component_order.map((id) => ({
  component_id: id,
  generated: Boolean(generatedById[id]),
  generation_source: generatedById[id]?.source || null,
  presence_confidence: (allComponents.find((c) => c.component_id === id) || {}).presence_confidence ?? null,
  anchor_hits: (allComponents.find((c) => c.component_id === id) || {}).anchor_hits ?? [],
}));

const wireframeImageMap = allComponents
  .slice()
  .sort((a, b) => (a.order || 0) - (b.order || 0))
  .map((c) => ({
    component_id: c.component_id,
    section_label: c.section_label || null,
