const mappedImagesTotal = wireframeImageMap.reduce((acc, c) => acc + (Array.isArray(c.images) ? c.images.length : 0), 0);

return [{
  json: {
    success: true,
    message: `HTML final generado. Componentes refinados por LLM: ${generatedCount}/${component_order.length}.`,
    pdf_url,
    render_png_url,
    session_id,
    response_mode: responseMode,
