    template_baseline: 'container_620_bg_E0E0E0',
    integrity: { final_equals_baseline: false },
    coordinate_origin: originTopLeft ? 'top_left' : 'bottom_left',
    components_generated: generatedCount,
    components_fallback: fallbackIds,
    parse_errors: parseErrors,
