const base = $json || {};
const inputHtml = String(base.html || base.html_final || '');

if (!inputHtml.trim()) return [{ json: { ...base, layout_adjusted: false, layout_reason: 'empty_html' } }];

let html = inputHtml;

const addCss = (style, css) => {
  const s = String(style || '').trim();
  if (!s) return css;
  if (s.toLowerCase().includes(css.split(':')[0].toLowerCase())) return s;
  return `${s}; ${css}`;
