// Asegura que NINGUNA imagen desborde su contenedor
html = html.replace(/<img\b([^>]*?)>/gi, (m, attrs) => {
  let out = attrs;

  const widthMatch = out.match(/\bwidth\s*=\s*"?(\d+)/i);
